function solve(s) {
    const n = s.length;
    const prefix_L = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        prefix_L[i] = prefix_L[i - 1] + (s[i - 1] === 'L' ? 1 : 0);
    }

    const T_after = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        T_after[i] = T_after[i + 1] + (s[i] === 'T' ? 1 : 0);
    }

    const C_before = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        C_before[i] = C_before[i - 1] + (s[i - 1] === 'C' ? 1 : 0);
    }

    const sum_C_T_after = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        if (s[i] === 'C') {
            sum_C_T_after[i] = sum_C_T_after[i + 1] + T_after[i];
        } else {
            sum_C_T_after[i] = sum_C_T_after[i + 1];
        }
    }

    let original_count = 0;
    for (let j = 0; j < n; j++) {
        if (s[j] === 'C') {
            original_count += prefix_L[j + 1] * T_after[j];
        }
    }

    let max_gain_L = 0;
    for (let i = 0; i <= n; i++) {
        max_gain_L = Math.max(max_gain_L, sum_C_T_after[i]);
    }

    let max_gain_C = 0;
    for (let i = 0; i <= n; i++) {
        const l = prefix_L[i];
        const t = T_after[i];
        max_gain_C = Math.max(max_gain_C, l * t);
    }

    let max_gain_T = 0;
    for (let i = 0; i <= n; i++) {
        const l = prefix_L[i];
        const c = C_before[i];
        max_gain_T = Math.max(max_gain_T, l * c);
    }

    const max_gain = Math.max(max_gain_L, max_gain_C, max_gain_T);
    return original_count + max_gain;
}
