        } else {
            sum_L_C_before[i + 1] = sum_L_C_before[i];
        }
    }

    let original_count = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'C') {
            original_count += prefix_L[i] * suffix_T[i + 1];
        }
    }

    let max_increase = 0;
    for (let pos = 0; pos <= n; pos++) {
        let temp = 0;
        temp = Math.max(temp, sum_C_T_after[pos]);
        temp = Math.max(temp, prefix_L[pos] * suffix_T[pos + 1]);
        temp = Math.max(temp, sum_L_C_before[pos]);
